const state = JSON.parse($input.first().json.stdout);
const now = new Date();
const il = new Intl.DateTimeFormat('en-CA', { timeZone: 'Asia/Jerusalem' });
const today = il.format(now); // YYYY-MM-DD

const isNew = state.session.status === 'ended';

if (isNew) {
  const lastDate = state.last_session.ended_at
    ? il.format(new Date(state.last_session.ended_at)) : null;
  state.session.number = (lastDate === today) ? state.session.number + 1 : 1;
  state.session.status = 'active';
  state.session.started_at = now.toISOString();
  state.flow = { position: null, current_task: null, timer: null, frozen: false };
}
state.session.last_message_at = now.toISOString();

return [{
  json: {
    isNew,
    archiveFile: state.last_session.archive_file || '',
    tomorrowNotes: state.last_session.tomorrow_notes || '',
    stateB64: Buffer.from(JSON.stringify(state, null, 2)).toString('base64')
  }
}];

