parameters.jsCode:
const raw = $('Read For Archive').first().json.stdout.split('---SPLIT---');
const state = JSON.parse(raw[0]);
const log = raw[1].trim();
const digest = $input.first().json.text || $input.first().json.content?.parts?.[0]?.text || '';

const active = state.session.status === 'active';
const now = new Date();
const il = new Intl.DateTimeFormat('en-CA', { timeZone: 'Asia/Jerusalem' });
const fname = `archive/${il.format(now)}-session${state.session.number}.md`;

if (active) {
  state.session.status = 'ended';
  state.last_session.archive_file = fname;
  state.last_session.ended_at = now.toISOString();
  state.last_session.tomorrow_notes = '';
}

const archive = digest.trim() + '\n\n<!-- RAW-LOG -->\n\n' + log + '\n';

return [{
  json: {
    active,
    fname,
    archiveB64: Buffer.from(archive).toString('base64'),
    stateB64: Buffer.from(JSON.stringify(state, null, 2)).toString('base64')
  }
}];

const resp = $input.first().json;
let text = resp.text || resp.content?.parts?.[0]?.text || '';

const markers = { pos: null, logs: [], freeze: false, unfreeze: false, rejected: [] };
text = text.replace(/\[\[POS:\s*(\S+?)\s*\]\]/g, (_, p) => { markers.pos = p; return ''; });
text = text.replace(/\[\[LOG:\s*(.+?)\s*\]\]/g, (_, l) => {
  const we = l.match(/^\s*window_end\s*=\s*(.+?)\s*$/);
  if (we) {
    const v = we[1].trim();
    const m = v.match(/^([01]?\d|2[0-3])(?::([0-5]\d))?$/); // H, HH, H:MM, HH:MM
    if (m) {
      markers.logs.push(`window_end=${m[1].padStart(2, '0')}:${m[2] || '00'}`);
    } else {
      markers.rejected.push(`window_end=${v}`);
    }
  } else {
    markers.logs.push(l);
  }
  return '';
});
text = text.replace(/\[\[FREEZE\]\]/g, () => { markers.freeze = true; return ''; });
text = text.replace(/\[\[UNFREEZE\]\]/g, () => { markers.unfreeze = true; return ''; });
text = text.trim();

// Telegram MarkdownV2 breaks on unescaped special chars; strip the offenders.
const safeText = text.replace(/[_*\[\]()~`>#+=|{}]/g, '');

return [{
  json: {
    cleanText: text,
    safeText: safeText,
    hasUpdate: markers.pos !== null || markers.logs.length > 0 || markers.freeze || markers.unfreeze,
    pos: markers.pos,
    freeze: markers.freeze,
    unfreeze: markers.unfreeze,
    rejectedWindowEnd: markers.rejected.join(', '),
    logsB64: Buffer.from(markers.logs.join('\n')).toString('base64')
  }
}];

// Read flow from the POST-Session-Logic state, not the raw on-disk Read State.
// On a NEW session, Session Logic resets flow to {position:null,frozen:false};
// reading Read State here would leak the previous (ended) session's position/frozen.
const state = JSON.parse(Buffer.from($('Session Logic').first().json.stateB64, 'base64').toString('utf-8'));
const flow = state.flow || { position: null, current_task: null, timer: null, frozen: false };
const pos = flow.position;
const frozen = flow.frozen;
const timer = flow.timer;

const keys = `הערה על מרקרים: המרקרים [[POS: N]], [[POS: done]], [[LOG: key=value]], [[FREEZE]], [[UNFREEZE]] הם חובה — עליך לכתוב אותם בסוף ההודעה כשמתאים, הם המנגנון שמניע את הזרימה. הם מוסרים אוטומטית לפני שיהודה רואה את ההודעה, אז אל תדאג שהוא יראה אותם. מפתחות מותרים ל-[[LOG]]: window_end, meds, tired, emotional, parked, project, first_task, day_list, timer_minutes, timer_cancel.
אימות window_end: הערך חייב להיות שעה תקינה בפורמט 24 שעות (00:00 עד 23:59), למשל 17:30 או 9:00. אם יהודה נותן ערך שאינו שעה תקינה (כמו "117" או "25:00") — אל תרשום [[LOG: window_end=...]], בקש ממנו בעדינות להבהיר את השעה, ואל תתקדם לשאלה הבאה עד שיש שעה תקינה.`;

const tone = `
--- טון ---
דבר ישיר, מדוד וחברי — אבל בלי התלהבות מזויפת. אסור סופרלטיבים ("מעולה", "מדהים", "וואו", "איזה יופי", "כל הכבוד") ואסור לפתוח תשובה בשבח או להחמיא סתם. אם יהודה עשה משהו, התייחס עניינית ולא בהתפעלות. אמן טוב מאתגר, משקף ושואל — לא מריע. חום כן, חנופה לא.`;

let block;
if (timer && timer.active) {
  block = `--- מצב טיימר פעיל ---
רשת הטיימר פועלת כרגע למשימה: "${timer.task || flow.current_task || 'משימה'}".
- אם יהודה כותב שהוא סיים ("סיימתי" / "גמרתי" / "done"): אשר בקצרה, רשום [[LOG: timer_cancel]], ושאל אם הוא רוצה לעבור למשימה הבאה או לקחת הפסקה.
- אם יהודה מציין בעיה או מבקש עזרה: הגב כמאמן, עזור לשחרר חסמים או לפרק את המשימה. ` + keys;
} else if (pos === null && !frozen) {
  block = `--- בקרת זרימה ---
אינך נמצא כרגע בצ'ק-אין.
- אם יהודה מאשר שהוא מוכן להתחיל צ'ק-אין (או אומר היי/בוקר טוב בסשן חדש): שאל את שאלה 1 מ-core/morning-flow.md (חלון עבודה), וסיים עם המרקר [[POS: 1]].
- אם יהודה מבקש להיזכר במשהו ("תזכיר לי...", "מה עשינו ב..."): חפש בסיכומים ובקבצים והשב עניינית. ` + keys;
} else if (frozen) {
  block = `--- בקרת זרימה: הזרימה מוקפאת ---
הצ'ק-אין הוקפא בשאלה מספר ${pos} כי יהודה לא היה מסוגל להמשיך.
- קבל אותו בחזרה בחום, בלי לחץ. אל תזרז.
- אם הוא מראה שהוא מוכן להמשיך עכשיו — חזור לאותה שאלה מספר ${pos} (בלי לדלג), וסיים עם המרקר [[UNFREEZE]] בלבד. אל תוסיף [[POS]] — המיקום נשאר ${pos}.
- אם הוא עדיין לא מסוגל (עייף, תקוע, צריך עוד זמן) — תן לגיטימציה מלאה, הישאר מוקפא, אל תוסיף שום מרקר.
- אם הוא רוצה לדבר על משהו אחר — פשוט תהיה נוכח ותקשיב, הישאר מוקפא. ` + keys;
} else {
  block = `--- בקרת זרימה: צ'ק-אין בוקר (שאלה ${pos} מתוך 11) ---
אתה מנהל את צ'ק-אין הבוקר. אתה נמצא בשאלה מספר ${pos}.
- המיקום בזרימה נקבע אך ורק לפי המספר ${pos}. אם היסטוריית השיחה נראית סותרת — התעלם, המספר קובע.
- השאלות לפי הסדר מ-core/morning-flow.md:
  1. חלון עבודה -> [[LOG: window_end=HH:MM]] -> עוברים ל-[[POS: 2]]
  2. ריטלין -> [[LOG: meds=yes/no]] -> עוברים ל-[[POS: 3]]
  3. עייפות -> אם עייף ולא מסוגל לעבוד -> לגיטימציה מלאה למנוחה + [[FREEZE]] (ללא [[POS]]). אחרת -> [[LOG: tired=no/yes]] -> עוברים ל-[[POS: 4]]
  4. רגשי -> תמיכה קלה, או הפניה למטפל אם כבד. אם תקוע -> [[FREEZE]]. אחרת -> עוברים ל-[[POS: 5]]
  5. נושא פתוח -> לסגור עכשיו -> [[FREEZE]]. לדחות -> [[LOG: parked=topic]] -> עוברים ל-[[POS: 6]]
  6. פרויקט -> נהל מול core/projects.md -> [[LOG: project=name]] -> עוברים ל-[[POS: 7]]
  7. המשימה הראשונה -> חדד לצעד קונקרטי, וודא ≤30 דקות -> [[LOG: first_task=text]] -> עוברים ל-[[POS: 8]]
  8. רשימת היום -> תפיסה מעורפלת -> [[LOG: day_list=text]] -> עוברים ל-[[POS: 9]]
  9. סקירת אתמול -> סקור בקצרה מסיכום אתמול/סשן קודם -> עוברים ל-[[POS: 10]]
  10. שער השלמות -> מוכנות לעבוד מתוך הנאה (מנדט כפול) -> עוברים ל-[[POS: 11]]
  11. משך ומוכנות -> שאל כמה זמן (בדוק מוכנות "מוכן להתחיל?") -> [[LOG: timer_minutes=N]] + [[POS: done]]

- כשיהודה עונה, תן תגובה קצרה ואנושית כמאמן, שאל את שאלה ${pos}, וסיים עם המרקר המתאים. ` + keys;
}

return [{ json: { flowBlock: block + tone } }];
